1. using Microsoft.AspNetCore.HttpOverrides;
2. 
3. var builder = WebApplication.CreateBuilder(args);
4. builder.Services.AddScoped<IUserService, UserService>();
5. // Fixed: Scoped service cannot be consumed from singleton via root provider.
6. // .NET 9 enables ValidateScopes in development by default, which catches this.
7. builder.Services.AddScoped<ICacheService>(sp =>
8.     new CacheService(sp.GetRequiredService<IUserService>()));
9. // Fixed: HttpClientFactory now uses SocketsHttpHandler by default in .NET 9.
10. // Casting to HttpClientHandler throws InvalidCastException.
11. builder.Services.AddHttpClient("api")
12.     .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });
13. // Fixed: .NET 9 ForwardedHeadersMiddleware ignores X-Forwarded-* from unknown proxies.
14. // Add trusted proxy addresses to KnownProxies or KnownNetworks.
15. builder.Services.Configure<ForwardedHeadersOptions>(options =>
16. {
17.     options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
18.     options.KnownNetworks.Clear();
19.     options.KnownProxies.Clear();
20. });
21. // Fixed: .NET 9 HttpClientFactory redacts all header values in Trace-level logs.
22. // Allowlist non-sensitive headers needed for debugging.
23. builder.Services.ConfigureHttpClientDefaults(b =>
24.     b.RedactLoggedHeaders(header =>
25.         header != "X-Request-Id" && header != "X-Forwarded-For"));
26. var app = builder.Build();
27. app.UseForwardedHeaders();
